import{_ as a,o as s,c as i,ae as l}from"./chunks/framework.BEtfQoF7.js";const k=JSON.parse('{"title":"Google Vertex AI에서 Claude Code 사용하기","description":"Google Vertex AI를 통해 Claude Code를 구성하는 방법을 알아봅니다. 설정, IAM 구성, 문제 해결을 포함합니다.","frontmatter":{"title":"Google Vertex AI에서 Claude Code 사용하기","description":"Google Vertex AI를 통해 Claude Code를 구성하는 방법을 알아봅니다. 설정, IAM 구성, 문제 해결을 포함합니다."},"headers":[],"relativePath":"google-vertex-ai.md","filePath":"google-vertex-ai.md","lastUpdated":1776205703000}'),t={name:"google-vertex-ai.md"};function o(r,e,n,d,p,h){return s(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="google-vertex-ai에서-claude-code-사용하기" tabindex="-1">Google Vertex AI에서 Claude Code 사용하기 <a class="header-anchor" href="#google-vertex-ai에서-claude-code-사용하기" aria-label="Permalink to &quot;Google Vertex AI에서 Claude Code 사용하기&quot;">​</a></h1><h2 id="prerequisites" tabindex="-1">사전 요구 사항 <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;사전 요구 사항 {#prerequisites}&quot;">​</a></h2><p>Vertex AI로 Claude Code를 구성하기 전에 다음을 확인하세요:</p><ul><li>결제가 활성화된 Google Cloud Platform (GCP) 계정</li><li>Vertex AI API가 활성화된 GCP 프로젝트</li><li>원하는 Claude 모델에 대한 액세스 (예: Claude Sonnet 4.6)</li><li>Google Cloud SDK (<code>gcloud</code>) 설치 및 구성</li><li>원하는 GCP 리전에 할당된 할당량</li></ul><p>자체 Vertex AI 자격 증명으로 로그인하려면 아래의 <a href="#sign-in-with-vertex-ai">Vertex AI로 로그인</a>을 따르세요. 팀 전체에 Claude Code를 배포하려면 <a href="#set-up-manually">수동 설정</a> 단계를 사용하고 배포 전에 <a href="#5-pin-model-versions">모델 버전을 고정</a>하세요.</p><h2 id="sign-in-with-vertex-ai" tabindex="-1">Vertex AI로 로그인 <a class="header-anchor" href="#sign-in-with-vertex-ai" aria-label="Permalink to &quot;Vertex AI로 로그인 {#sign-in-with-vertex-ai}&quot;">​</a></h2><p>Google Cloud 자격 증명이 있고 Vertex AI를 통해 Claude Code를 사용하려면, 로그인 마법사가 안내합니다. GCP 측 사전 요구 사항은 프로젝트당 한 번 완료하면 되며, 마법사가 Claude Code 측을 처리합니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>Vertex AI 설정 마법사는 Claude Code v2.1.98 이상이 필요합니다. <code>claude --version</code>으로 확인하세요.</p></div><h3 id="_1단계-gcp-프로젝트에서-claude-모델-활성화" tabindex="-1">1단계: GCP 프로젝트에서 Claude 모델 활성화 <a class="header-anchor" href="#_1단계-gcp-프로젝트에서-claude-모델-활성화" aria-label="Permalink to &quot;1단계: GCP 프로젝트에서 Claude 모델 활성화&quot;">​</a></h3><p>프로젝트에 <a href="#1-enable-vertex-ai-api">Vertex AI API를 활성화</a>한 다음, <a href="https://console.cloud.google.com/vertex-ai/model-garden" target="_blank" rel="noreferrer">Vertex AI Model Garden</a>에서 원하는 Claude 모델에 대한 액세스를 요청하세요. 계정에 필요한 권한은 <a href="#iam-configuration">IAM 구성</a>을 참조하세요.</p><h3 id="_2단계-claude-code를-시작하고-vertex-ai-선택" tabindex="-1">2단계: Claude Code를 시작하고 Vertex AI 선택 <a class="header-anchor" href="#_2단계-claude-code를-시작하고-vertex-ai-선택" aria-label="Permalink to &quot;2단계: Claude Code를 시작하고 Vertex AI 선택&quot;">​</a></h3><p><code>claude</code>를 실행합니다. 로그인 프롬프트에서 <strong>3rd-party platform</strong>을 선택한 다음 <strong>Google Vertex AI</strong>를 선택합니다.</p><h3 id="_3단계-마법사-프롬프트-따르기" tabindex="-1">3단계: 마법사 프롬프트 따르기 <a class="header-anchor" href="#_3단계-마법사-프롬프트-따르기" aria-label="Permalink to &quot;3단계: 마법사 프롬프트 따르기&quot;">​</a></h3><p>Google Cloud에 인증하는 방법을 선택합니다: <code>gcloud</code>의 Application Default Credentials, 서비스 계정 키 파일, 또는 환경에 이미 있는 자격 증명. 마법사가 프로젝트와 리전을 감지하고, 프로젝트에서 호출할 수 있는 Claude 모델을 확인하며, 고정할 수 있게 합니다. 결과를 <a href="/claude-code-docs-ko/settings.html">사용자 설정 파일</a>의 <code>env</code> 블록에 저장하므로 직접 환경 변수를 내보낼 필요가 없습니다.</p><p>로그인한 후 언제든지 <code>/setup-vertex</code>를 실행하여 마법사를 다시 열고 자격 증명, 프로젝트, 리전 또는 모델 고정을 변경할 수 있습니다.</p><h2 id="region-configuration" tabindex="-1">리전 구성 <a class="header-anchor" href="#region-configuration" aria-label="Permalink to &quot;리전 구성 {#region-configuration}&quot;">​</a></h2><p>Claude Code는 Vertex AI <a href="https://cloud.google.com/blog/products/ai-machine-learning/global-endpoint-for-claude-models-generally-available-on-vertex-ai" target="_blank" rel="noreferrer">글로벌</a> 및 리전 엔드포인트 모두에서 사용할 수 있습니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>Vertex AI는 모든 <a href="https://cloud.google.com/vertex-ai/generative-ai/docs/learn/locations#genai-partner-models" target="_blank" rel="noreferrer">리전</a>이나 <a href="https://cloud.google.com/vertex-ai/generative-ai/docs/partner-models/use-partner-models#supported_models" target="_blank" rel="noreferrer">글로벌 엔드포인트</a>에서 Claude Code 기본 모델을 지원하지 않을 수 있습니다. 지원되는 리전으로 전환하거나, 리전 엔드포인트를 사용하거나, 지원되는 모델을 지정해야 할 수 있습니다.</p></div><h2 id="set-up-manually" tabindex="-1">수동 설정 <a class="header-anchor" href="#set-up-manually" aria-label="Permalink to &quot;수동 설정 {#set-up-manually}&quot;">​</a></h2><p>마법사 대신 환경 변수를 통해 Vertex AI를 구성하려면(예: CI 또는 스크립트로 된 엔터프라이즈 배포), 아래 단계를 따르세요.</p><h3 id="1-enable-vertex-ai-api" tabindex="-1">1. Vertex AI API 활성화 <a class="header-anchor" href="#1-enable-vertex-ai-api" aria-label="Permalink to &quot;1. Vertex AI API 활성화 {#1-enable-vertex-ai-api}&quot;">​</a></h3><p>GCP 프로젝트에서 Vertex AI API를 활성화합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 프로젝트 ID 설정</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcloud</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR-PROJECT-ID</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vertex AI API 활성화</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcloud</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aiplatform.googleapis.com</span></span></code></pre></div><h3 id="2-request-model-access" tabindex="-1">2. 모델 액세스 요청 <a class="header-anchor" href="#2-request-model-access" aria-label="Permalink to &quot;2. 모델 액세스 요청 {#2-request-model-access}&quot;">​</a></h3><p>Vertex AI에서 Claude 모델에 대한 액세스를 요청합니다:</p><ol><li><a href="https://console.cloud.google.com/vertex-ai/model-garden" target="_blank" rel="noreferrer">Vertex AI Model Garden</a>으로 이동합니다</li><li>&quot;Claude&quot; 모델을 검색합니다</li><li>원하는 Claude 모델에 대한 액세스를 요청합니다 (예: Claude Sonnet 4.6)</li><li>승인을 기다립니다 (24-48시간 소요될 수 있음)</li></ol><h3 id="3-configure-gcp-credentials" tabindex="-1">3. GCP 자격 증명 구성 <a class="header-anchor" href="#3-configure-gcp-credentials" aria-label="Permalink to &quot;3. GCP 자격 증명 구성 {#3-configure-gcp-credentials}&quot;">​</a></h3><p>Claude Code는 표준 Google Cloud 인증을 사용합니다.</p><p>자세한 내용은 <a href="https://cloud.google.com/docs/authentication" target="_blank" rel="noreferrer">Google Cloud 인증 문서</a>를 참조하세요.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>인증 시 Claude Code는 <code>ANTHROPIC_VERTEX_PROJECT_ID</code> 환경 변수의 프로젝트 ID를 자동으로 사용합니다. 이를 재정의하려면 다음 환경 변수 중 하나를 설정하세요: <code>GCLOUD_PROJECT</code>, <code>GOOGLE_CLOUD_PROJECT</code>, 또는 <code>GOOGLE_APPLICATION_CREDENTIALS</code>.</p></div><h3 id="4-configure-claude-code" tabindex="-1">4. Claude Code 구성 <a class="header-anchor" href="#4-configure-claude-code" aria-label="Permalink to &quot;4. Claude Code 구성 {#4-configure-claude-code}&quot;">​</a></h3><p>다음 환경 변수를 설정합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vertex AI 통합 활성화</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_USE_VERTEX</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLOUD_ML_REGION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_VERTEX_PROJECT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">YOUR-PROJECT-ID</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 선택 사항: 커스텀 엔드포인트 또는 게이트웨이용 Vertex 엔드포인트 URL 재정의</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># export ANTHROPIC_VERTEX_BASE_URL=https://aiplatform.googleapis.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 선택 사항: 필요한 경우 프롬프트 캐싱 비활성화</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DISABLE_PROMPT_CACHING</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CLOUD_ML_REGION=global일 때, 글로벌 엔드포인트를 지원하지 않는 모델의 리전 재정의</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VERTEX_REGION_CLAUDE_HAIKU_4_5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">us-east5</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VERTEX_REGION_CLAUDE_4_6_SONNET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">europe-west1</span></span></code></pre></div><p>대부분의 모델 버전에는 대응하는 <code>VERTEX_REGION_CLAUDE_*</code> 변수가 있습니다. 전체 목록은 <a href="/claude-code-docs-ko/env-vars.html">환경 변수 참조</a>를 확인하세요. <a href="https://console.cloud.google.com/vertex-ai/model-garden" target="_blank" rel="noreferrer">Vertex Model Garden</a>에서 어떤 모델이 글로벌 엔드포인트와 리전 전용을 지원하는지 확인하세요.</p><p><a href="https://platform.claude.com/docs/en/build-with-claude/prompt-caching" target="_blank" rel="noreferrer">프롬프트 캐싱</a>은 <code>cache_control</code> ephemeral 플래그를 지정하면 자동으로 지원됩니다. 비활성화하려면 <code>DISABLE_PROMPT_CACHING=1</code>을 설정하세요. 더 높은 속도 제한을 원하면 Google Cloud 지원에 문의하세요. Vertex AI를 사용할 때 인증이 Google Cloud 자격 증명을 통해 처리되므로 <code>/login</code> 및 <code>/logout</code> 명령은 비활성화됩니다.</p><h3 id="5-pin-model-versions" tabindex="-1">5. 모델 버전 고정 <a class="header-anchor" href="#5-pin-model-versions" aria-label="Permalink to &quot;5. 모델 버전 고정 {#5-pin-model-versions}&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">주의</p><p>여러 사용자에게 배포할 때는 특정 모델 버전을 고정하세요. 고정하지 않으면 <code>sonnet</code> 및 <code>opus</code>와 같은 모델 별칭이 최신 버전으로 확인되며, Anthropic이 업데이트를 릴리스할 때 Vertex AI 프로젝트에서 아직 활성화되지 않았을 수 있습니다. Claude Code는 최신 버전을 사용할 수 없을 때 시작 시 <a href="#startup-model-checks">이전 버전으로 폴백</a>하지만, 고정하면 사용자가 새 모델로 이동하는 시점을 제어할 수 있습니다.</p></div><p>이러한 환경 변수를 특정 Vertex AI 모델 ID로 설정합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_OPUS_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;claude-opus-4-6&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_SONNET_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;claude-sonnet-4-6&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_HAIKU_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;claude-haiku-4-5@20251001&#39;</span></span></code></pre></div><p>현재 및 레거시 모델 ID는 <a href="https://platform.claude.com/docs/en/about-claude/models/overview" target="_blank" rel="noreferrer">모델 개요</a>를 참조하세요. 환경 변수 전체 목록은 <a href="/claude-code-docs-ko/model-config.html#pin-models-for-third-party-deployments">모델 구성</a>을 참조하세요.</p><p>고정 변수가 설정되지 않은 경우 Claude Code가 사용하는 기본 모델:</p><table tabindex="0"><thead><tr><th style="text-align:left;">모델 유형</th><th style="text-align:left;">기본값</th></tr></thead><tbody><tr><td style="text-align:left;">기본 모델</td><td style="text-align:left;"><code>claude-sonnet-4-5@20250929</code></td></tr><tr><td style="text-align:left;">소형/빠른 모델</td><td style="text-align:left;"><code>claude-haiku-4-5@20251001</code></td></tr></tbody></table><p>모델을 추가로 커스터마이즈하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;claude-opus-4-6&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_HAIKU_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;claude-haiku-4-5@20251001&#39;</span></span></code></pre></div><h2 id="startup-model-checks" tabindex="-1">시작 시 모델 확인 <a class="header-anchor" href="#startup-model-checks" aria-label="Permalink to &quot;시작 시 모델 확인 {#startup-model-checks}&quot;">​</a></h2><p>Vertex AI가 구성된 상태에서 Claude Code가 시작되면, 프로젝트에서 사용하려는 모델에 접근할 수 있는지 확인합니다. 이 확인은 Claude Code v2.1.98 이상이 필요합니다.</p><p>현재 Claude Code 기본값보다 오래된 모델 버전을 고정했고 프로젝트에서 최신 버전을 호출할 수 있는 경우, Claude Code가 고정을 업데이트하라는 메시지를 표시합니다. 수락하면 새 모델 ID가 <a href="/claude-code-docs-ko/settings.html">사용자 설정 파일</a>에 기록되고 Claude Code가 재시작됩니다. 거부하면 다음 기본 버전 변경 시까지 기억됩니다.</p><p>모델을 고정하지 않았고 현재 기본값을 프로젝트에서 사용할 수 없는 경우, Claude Code는 현재 세션에 대해 이전 버전으로 폴백하고 알림을 표시합니다. 폴백은 유지되지 않습니다. <a href="https://console.cloud.google.com/vertex-ai/model-garden" target="_blank" rel="noreferrer">Model Garden</a>에서 최신 모델을 활성화하거나 <a href="#5-pin-model-versions">버전을 고정</a>하여 선택을 영구적으로 만드세요.</p><h2 id="iam-configuration" tabindex="-1">IAM 구성 <a class="header-anchor" href="#iam-configuration" aria-label="Permalink to &quot;IAM 구성 {#iam-configuration}&quot;">​</a></h2><p>필요한 IAM 권한을 할당합니다:</p><p><code>roles/aiplatform.user</code> 역할에는 필요한 권한이 포함되어 있습니다:</p><ul><li><code>aiplatform.endpoints.predict</code> - 모델 호출 및 토큰 카운팅에 필요</li></ul><p>더 제한적인 권한을 위해 위의 권한만 포함하는 커스텀 역할을 만드세요.</p><p>자세한 내용은 <a href="https://cloud.google.com/vertex-ai/docs/general/access-control" target="_blank" rel="noreferrer">Vertex IAM 문서</a>를 참조하세요.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>비용 추적과 액세스 제어를 간소화하기 위해 Claude Code 전용 GCP 프로젝트를 만드세요.</p></div><h2 id="1m-token-context-window" tabindex="-1">1M 토큰 컨텍스트 윈도우 <a class="header-anchor" href="#1m-token-context-window" aria-label="Permalink to &quot;1M 토큰 컨텍스트 윈도우 {#1m-token-context-window}&quot;">​</a></h2><p>Claude Opus 4.6, Sonnet 4.6, Sonnet 4.5, Sonnet 4는 Vertex AI에서 <a href="https://platform.claude.com/docs/en/build-with-claude/context-windows#1m-token-context-window" target="_blank" rel="noreferrer">1M 토큰 컨텍스트 윈도우</a>를 지원합니다. Claude Code는 1M 모델 변형을 선택하면 자동으로 확장된 컨텍스트 윈도우를 활성화합니다.</p><p>고정된 모델에 1M 컨텍스트 윈도우를 활성화하려면 모델 ID에 <code>[1m]</code>을 추가하세요. 자세한 내용은 <a href="/claude-code-docs-ko/model-config.html#pin-models-for-third-party-deployments">서드파티 배포를 위한 모델 고정</a>을 참조하세요.</p><h2 id="troubleshooting" tabindex="-1">문제 해결 <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;문제 해결 {#troubleshooting}&quot;">​</a></h2><p>할당량 문제가 발생하는 경우:</p><ul><li><a href="https://cloud.google.com/docs/quotas/view-manage" target="_blank" rel="noreferrer">Cloud Console</a>을 통해 현재 할당량을 확인하거나 할당량 증가를 요청하세요</li></ul><p>&quot;model not found&quot; 404 오류가 발생하는 경우:</p><ul><li><a href="https://console.cloud.google.com/vertex-ai/model-garden" target="_blank" rel="noreferrer">Model Garden</a>에서 모델이 활성화되어 있는지 확인하세요</li><li>지정한 리전에 대한 액세스가 있는지 확인하세요</li><li><code>CLOUD_ML_REGION=global</code>을 사용하는 경우, <a href="https://console.cloud.google.com/vertex-ai/model-garden" target="_blank" rel="noreferrer">Model Garden</a>의 &quot;Supported features&quot;에서 모델이 글로벌 엔드포인트를 지원하는지 확인하세요. 글로벌 엔드포인트를 지원하지 않는 모델의 경우: <ul><li><code>ANTHROPIC_MODEL</code> 또는 <code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code>을 통해 지원되는 모델을 지정하거나</li><li><code>VERTEX_REGION_&lt;MODEL_NAME&gt;</code> 환경 변수를 사용하여 리전 엔드포인트를 설정하세요</li></ul></li></ul><p>429 오류가 발생하는 경우:</p><ul><li>리전 엔드포인트의 경우, 기본 모델과 소형/빠른 모델이 선택한 리전에서 지원되는지 확인하세요</li><li>더 나은 가용성을 위해 <code>CLOUD_ML_REGION=global</code>로 전환하는 것을 고려하세요</li></ul><h2 id="additional-resources" tabindex="-1">추가 리소스 <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;추가 리소스 {#additional-resources}&quot;">​</a></h2><ul><li><a href="https://cloud.google.com/vertex-ai/docs" target="_blank" rel="noreferrer">Vertex AI 문서</a></li><li><a href="https://cloud.google.com/vertex-ai/pricing" target="_blank" rel="noreferrer">Vertex AI 가격</a></li><li><a href="https://cloud.google.com/vertex-ai/docs/quotas" target="_blank" rel="noreferrer">Vertex AI 할당량 및 제한</a></li></ul>`,67)])])}const u=a(t,[["render",o]]);export{k as __pageData,u as default};
